const m = $json;

// El trigger de Outlook puede entregar el correo "simplificado" (from es un
// string, to es [string], solo bodyPreview) o completo (from.emailAddress.address,
// toRecipients, body.content), segun el toggle "Simplify" del nodo. Soporta ambos.
// email() saca la direccion limpia aunque venga como "Nombre <correo@dominio>".
const email = (v) => {
  const s = (typeof v === 'string' ? v : (v?.emailAddress?.address ?? '')).trim();
  const mm = s.match(/<([^>]+)>/);
  return (mm ? mm[1] : s).trim().toLowerCase();
};

const remitente = email(m.from) || email(m.sender) || '';

// Correos sin remitente real (notificaciones del propio Microsoft, avisos del
// sistema) no son consultas: se descartan. Devolver [] corta el flujo para este
// item, sin marcarlo como error.
if (!remitente) return [];

// Sin el id del mensaje no se puede responder en el hilo: Graph exige el id
// exacto y, si va vacio, devuelve 400 "ErrorInvalidIdMalformed". Se descarta
// aqui en vez de dejar que reviente el nodo de Outlook al final del flujo.
const mensajeId = m.id ?? m.messageId ?? '';
if (!mensajeId) return [];

const cuentaSoporte =
  (Array.isArray(m.to) ? email(m.to[0]) : '') ||
  email(m.toRecipients?.[0]?.emailAddress?.address) ||
  '';

// Las respuestas que envia el propio asistente (y los correos de delegacion y
// de aviso de ticket) salen desde una cuenta de soporte; si el trigger las
// levanta, no deben reprocesarse: causarian bucles. Este es el primer filtro;
// el cerebro tiene ademas la lista blanca CUENTAS_SOPORTE, que atrapa tambien
// los avisos dirigidos a un agente (cuyo 'to' NO es la cuenta de soporte).
if (cuentaSoporte && remitente === cuentaSoporte) return [];

const cuerpoCompleto = m.body?.content ?? '';
const cuerpo = cuerpoCompleto || m.bodyPreview || '';
const cuerpoTruncado = !cuerpoCompleto && (m.bodyPreview ?? '').length >= 250;

return [{
  json: {
    hiloId: m.conversationId,
    mensajeId,
    remitente,
    cuentaSoporte,
    asunto: m.subject ?? '',
    cuerpo,
    cuerpoTruncado,
    adjuntos: [],
  },
}];
